    // D_i must satisfy D_i >= 0 and D_i >= D_{i-1} + (nums[i-1] - nums[i]).
    let dPrev = 0; 
    let totalSumX = 0;

    // We iterate through all elements, calculating D_i and the associated cost contribution.
    for (let i = 0; i < n; i++) {
        let dCurr;

        if (i === 0) {
            // D_0 must be at least 0. We choose the minimum, D_0 = 0.
            dCurr = 0;
        } else {
            // R_{i-1} = nums[i-1] - nums[i]
            const requiredIncreaseDifference = nums[i - 1] - nums[i];

            // Calculate the minimum required D_i
            // D_i = max(0, D_{i-1} + R_{i-1})
            dCurr = Math.max(0, dPrev + requiredIncreaseDifference);
