        // The total sum of x's is the sum of all positive jumps in the D sequence: S = sum(max(0, D_i - D_{i-1}))
        // For i=0, D_{-1}=0, D_0=0, so the contribution is 0.
        const costContribution = Math.max(0, dCurr - dPrev);
        totalSumX += costContribution;

        // Update D_prev for the next iteration
        dPrev = dCurr;
    }

    return totalSumX;
}

